{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Product List",
  "description": "A list of commerce products generated by the AI service.",
  "type": "object",
  "properties": {
    "products": {
      "type": "array",
      "description": "An array of generated product objects.",
      "items": {
        "title": "Product",
        "type": "object",
        "properties": {
          "name": {
            "description": "Multilingual product names keyed by language code.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            },
            "minProperties": 1
          },
          "description": {
            "description": "Multilingual long descriptions keyed by language code.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "shortDescription": {
            "description": "Multilingual short descriptions keyed by language code.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "urls": {
            "description": "Multilingual URL slugs keyed by language code (lowercase, hyphen-separated).",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            },
            "minProperties": 1
          },
          "baseSku": {
            "description": "Base SKU without variant codes.",
            "type": "string"
          },
          "productType": {
            "description": "The product type, expected to be 'simple'.",
            "type": "string"
          },
          "skus": {
            "description": "Base SKU objects for the product.",
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "sku": {
                  "description": "The SKU of the product.",
                  "type": "string"
                },
                "cost": {
                  "description": "The cost of the product.",
                  "type": "number"
                },
                "price": {
                  "description": "The price of the product.",
                  "type": "number"
                },
                "inventoryLevel": {
                  "description": "Available inventory quantity.",
                  "type": "integer"
                },
                "published": {
                  "description": "Whether the SKU is published.",
                  "type": "boolean"
                },
                "purchasable": {
                  "description": "Whether the SKU is purchasable.",
                  "type": "boolean"
                },
                "neverExpire": {
                  "description": "Whether the SKU never expires.",
                  "type": "boolean"
                },
                "externalReferenceCode": {
                  "description": "Unique external reference for the SKU.",
                  "type": "string"
                }
              },
              "required": [
                "sku",
                "cost",
                "price",
                "inventoryLevel",
                "published",
                "purchasable",
                "neverExpire",
                "externalReferenceCode"
              ],
              "additionalProperties": false
            },
            "minItems": 1
          },
          "specifications": {
            "description": "Product specifications as key-value pairs.",
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "key": {
                  "description": "Specification name.",
                  "type": "string"
                },
                "value": {
                  "description": "Multilingual specification value keyed by language code.",
                  "type": "object",
                  "additionalProperties": {
                    "type": "string"
                  }
                }
              },
              "required": [
                "key",
                "value"
              ],
              "additionalProperties": false
            }
          },
          "options": {
            "description": "Product options (e.g. Color, Size) with possible values.",
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "name": {
                  "description": "Option name, such as 'Color' or 'Size'.",
                  "type": "string"
                },
                "values": {
                  "description": "List of possible values for this option.",
                  "type": "array",
                  "items": {
                    "type": "string"
                  },
                  "minItems": 1
                }
              },
              "required": [
                "name",
                "values"
              ],
              "additionalProperties": false
            }
          },
          "skuVariants": {
            "description": "SKU variants generated from option combinations.",
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "sku": {
                  "description": "Variant SKU (baseSku plus variant codes).",
                  "type": "string"
                },
                "options": {
                  "description": "The specific option combination, keyed by option name.",
                  "type": "object",
                  "additionalProperties": {
                    "type": "string"
                  },
                  "minProperties": 1
                },
                "priceModifier": {
                  "description": "Percentage adjustment from base price, e.g. -0.15 to 0.3.",
                  "type": "number"
                },
                "inStock": {
                  "description": "Whether this variant is in stock.",
                  "type": "boolean"
                }
              },
              "required": [
                "sku",
                "options",
                "priceModifier",
                "inStock"
              ],
              "additionalProperties": false
            }
          },
          "attachments": {
            "description": "Attachment file names such as manuals or warranties.",
            "type": "array",
            "items": {
              "type": "string"
            }
          },
          "metaDescription": {
            "description": "Multilingual SEO descriptions keyed by language code.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "metaKeyword": {
            "description": "Multilingual SEO keywords keyed by language code (comma-separated).",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "metaTitle": {
            "description": "Multilingual SEO titles keyed by language code.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "externalReferenceCode": {
            "description": "Unique external reference for the product.",
            "type": "string"
          }
        },
        "required": [
          "name",
          "description",
          "shortDescription",
          "urls",
          "baseSku",
          "productType",
          "skus",
          "externalReferenceCode"
        ],
        "additionalProperties": true
      }
    }
  },
  "required": ["products"]
}
